// ---------------------------------------------------------------------------
// Kernel C: apply clarity — upsample blurred L to full res, compute detail,
//           reconstruct RGB with modified L only.
// ---------------------------------------------------------------------------
extern "C"
__global__ void clarity_apply_kernel(
    const float* __restrict__ rgb_in,      // [full_w * full_h * 3]
